VALUES
  ('promotion-d0d1b9a2-moex-00143', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '企業買回庫藏股時，以下何種情況不會發生？', '["現金減少", "每股盈餘增加", "權益報酬率增加", "已發行普通股股本減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00144', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '甲公司於 X0 年年底併購乙公司。併購時之契約明訂，兩公司於合併後兩個會計年度的稅後淨利 皆高於$500,000時，會於X3年額外發行60,000股給予原乙公司之股東。併購後甲公司之X1年 的本期淨利為$540,000，年度在外流通股數之加權平均為240,000股。試問甲公司X1年之稀釋每 股盈餘之金額為何？', '["$2.25", "$2.08", "$1.80", "$1.67"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00145', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年年底宣告發放現金股利$600,000。下列為甲公司於X1年年底之部分權益資料：特別 股（8%，面額$100，流通在外股數為12,000股），普通股（面額$10，流通在外股數為60,000股）， 另有來自普通股溢價之資本公積$400,000 與換算國外營運機構財務報表所產生之兌換差額 $50,000。甲公司之特別股為非累積，可參加至12%。試問，普通股每股可分得之股利金額？', '["$7.6", "$5.2", "$12", "$0.1"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00146', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X9年7月1日以$20億取得專利權A。專利權A的法定保護年限剩餘15年，但甲公司 預估專利權A的經濟耐用年限僅有10年。甲公司於X9年12月31日財務報導日以直線法攤銷 該專利權A，攤銷年限設為15年。試問，其違反下列何種資訊品質特性或原則？', '["重大性", "時效性", "忠實表述", "可比性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00147', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '下列有關無形資產之敘述何者正確？', '["企業可認列其內部生成之品牌價值為資產", "企業每年須對商譽做減損測試並且認列攤銷費用", "企業須攤銷有確定耐用年限之無形資產", "企業於專利權侵權訴訟勝訴時，所支出之費用可認列為資產"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00148', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '古坑公司於 X2 年初按面額發行可賣回公司債 3,600 張，每張面額$1,000，5 年期，到期日為 X6 年 12月 31日，票面利率 3%，每年 12月 31 日付息一次。公司債合約中規定，持有人於 X4年3月1日及X5年3月1日有權利按面額之108%加計應計利息賣回公司債。試問古坑公 司在X3年12月31日資產負債表中對此流通在外可賣回公司債應分類為何？', '["非流動負債", "流動負債", "權益", "非控制權益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00149', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '台中公司X2年帳上的相關資訊如下： 透過其他綜合損益按公允價值衡量之債務工具投資未實現評價利益 $36,000 確定福利計畫的再衡量數 24,000(貸方) 國外營運機構財務報表換算成本國貨幣所產生的兌換損失 18,000 現金流量避險中屬有效避險部分之避險工具利益 5,000 機器設備的重估價損失 6,000 透過其他綜合損益按公允價值衡量之權益工具投資未實現評價損失 12,000 專利權的重估增值 27,000 投資性不動產之公允價值變動損失 28,000 試問：台中公司應於 X2 年度綜合損益表中報導後續可能重分類至損益的其他綜合損益項目總金 額為何（不考慮所得稅的影響）？', '["$56,000", "$33,000", "$39,000", "$23,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00150', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '下列不屬於投資性不動產者共有幾項？ ⑴為獲取長期資本增值而持有的土地 ⑵企業所持有與建築物相關的使用權資產，並以營業租賃出租的建築物 ⑶準備以營業租賃的方式招租，但目前暫時空置尚未出租的辦公大樓 ⑷企業所持有提供予員工使用並收取租金的宿舍 ⑸為供正常營業過程出售而仍於開發中的土地 ⑹以營業租賃的方式出租予他人的機器設備', '["1項", "2項", "3項", "4項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00151', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '正光公司於X2年1月1日發行每股面額$10的累積特別股50,000股，取得價款$503,270，並支 付股票發行成本$30,000，滿 3 年時正光公司必須按每股$10 贖回全部特別股。特別股股利率為 4%，每年 12 月 31 日支付股利，公司有盈餘時即須支付該股利，並無裁量權利。特別股發行當 日，正光公司發行類似品質之3年期4%債券的市場利率為6%。試問X3年12月31日正光公司 支付該特別股股利時，帳上應如何記錄？', '["借：保留盈餘27,320", "借：利息費用28,900", "借：保留盈餘20,000", "借：利息費用29,434"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00152', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '皇家公司於X3年7月12日決議辦理現金增資150,000股，保留員工認股數為15,000股，當日員 工與公司對認購計畫已有共識。皇家公司採用選擇權評價模式，估計所給與認購新股之權利在X3 年 7 月 12 日的每單位公允價值為$8，當時公司股價每股$66，員工認購價每股$60。若皇家公司 的員工於X3年8月15日共認購8,000股，但兩個月後現金增資失敗，皇家公司亦退回股款。試 問皇家公司X3年應認列的薪資費用為何？', '["$0", "$64,000", "$120,000", "$480,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL)
